import{_ as a,c as t,o as i,ae as l}from"./chunks/framework.Bw7rlmih.js";const p=JSON.parse('{"title":"CP-006: Cache Engine Semantics","description":"","frontmatter":{},"headers":[],"relativePath":"control-plane/atomic/CP-006-cache-engine-semantics.md","filePath":"control-plane/atomic/CP-006-cache-engine-semantics.md"}'),o={name:"control-plane/atomic/CP-006-cache-engine-semantics.md"};function c(r,e,n,s,d,h){return i(),t("div",null,e[0]||(e[0]=[l('<h1 id="cp-006-cache-engine-semantics" tabindex="-1">CP-006: Cache Engine Semantics <a class="header-anchor" href="#cp-006-cache-engine-semantics" aria-label="Permalink to &quot;CP-006: Cache Engine Semantics&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Define strict caching behavior for remote connector data.</p><h2 id="inputs-outputs" tabindex="-1">Inputs / Outputs <a class="header-anchor" href="#inputs-outputs" aria-label="Permalink to &quot;Inputs / Outputs&quot;">​</a></h2><ul><li>Input: connector read request.</li><li>Output: cache hit/miss decision + value + freshness state.</li></ul><h2 id="public-interfaces" tabindex="-1">Public Interfaces <a class="header-anchor" href="#public-interfaces" aria-label="Permalink to &quot;Public Interfaces&quot;">​</a></h2><ul><li><code>GET /v1/cache/entries/{key}</code> (internal/admin)</li><li><code>POST /v1/cache/invalidate</code></li><li><code>konfigo cache stats|invalidate</code></li></ul><h2 id="mandatory-rules" tabindex="-1">Mandatory Rules <a class="header-anchor" href="#mandatory-rules" aria-label="Permalink to &quot;Mandatory Rules&quot;">​</a></h2><ol><li><strong>Lease/TTL-aware cache</strong></li></ol><ul><li>Never cache dynamic secrets beyond lease expiry.</li><li>Effective TTL = <code>min(config_ttl, provider_ttl_or_lease)</code>.</li></ul><ol start="2"><li><strong>Stale-While-Revalidate (SWR) + watch invalidation</strong></li></ol><ul><li>Return stale for bounded SWR window when enabled.</li><li>Trigger async revalidation.</li><li>Invalidate on provider watch signal where available.</li></ul><h2 id="provider-watch-hooks" tabindex="-1">Provider Watch Hooks <a class="header-anchor" href="#provider-watch-hooks" aria-label="Permalink to &quot;Provider Watch Hooks&quot;">​</a></h2><ul><li>Consul: blocking query index advance</li><li>etcd: watch revision event</li><li>Redis: pub/sub channel event</li><li>AWS AppConfig: version token change</li><li>Optional hooks for Vault version checks</li></ul><h2 id="data-contracts" tabindex="-1">Data Contracts <a class="header-anchor" href="#data-contracts" aria-label="Permalink to &quot;Data Contracts&quot;">​</a></h2><h2 id="cache-key-contract" tabindex="-1">Cache Key Contract <a class="header-anchor" href="#cache-key-contract" aria-label="Permalink to &quot;Cache Key Contract&quot;">​</a></h2><p><code>&lt;provider&gt;:&lt;scope&gt;:&lt;location&gt;:&lt;selector&gt;:&lt;auth_context_hash&gt;</code></p><h2 id="cache-entry-contract" tabindex="-1">Cache Entry Contract <a class="header-anchor" href="#cache-entry-contract" aria-label="Permalink to &quot;Cache Entry Contract&quot;">​</a></h2><ul><li><code>key</code></li><li><code>valueHash</code></li><li><code>insertedAt</code></li><li><code>expiresAt</code></li><li><code>staleUntil</code></li><li><code>providerVersion</code></li><li><code>leaseInfo</code></li><li><code>lastRevalidateAt</code></li></ul><h2 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h2><ul><li>Secrets are stored encrypted in cache at rest.</li><li>No cache entry outlives lease expiration for dynamic secrets.</li><li>SWR is disabled by default for protected scopes unless explicitly enabled.</li></ul><h2 id="failure-modes" tabindex="-1">Failure Modes <a class="header-anchor" href="#failure-modes" aria-label="Permalink to &quot;Failure Modes&quot;">​</a></h2><ul><li><code>500 cache_encryption_failure</code></li><li><code>500 cache_state_corruption</code></li><li><code>503 revalidation_failed</code> (with stale fallback if allowed)</li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance Criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance Criteria&quot;">​</a></h2><ol><li>Dynamic Vault secret with 30s lease expires from cache &lt;=30s.</li><li>SWR returns stale value and triggers background refresh.</li><li>Watch invalidation removes stale entry within configured latency budget.</li><li>Cache metrics expose hit/miss, stale returns, and revalidation failures.</li></ol><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Multi-layer global cache topology tuning.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>CP-005 connectors.</li></ul>',29)]))}const f=a(o,[["render",c]]);export{p as __pageData,f as default};
